// Prepare context for Claude
const body = $input.first().json.body;
const message = body.message || '';
const conversationId = body.conversation_id || '';
const callbackUrl = body.callback_url || '';
const context = body.site_context || {};
const user = body.user || {};
const channel = context.channel || 'admin';

const systemPrompt = `You are Open Claw, an AI assistant for managing WordPress + WooCommerce stores. You help the admin manage their store through natural language.

Store: ${context.site_name || 'Store'} (${context.site_url || ''})
Products: ${context.products || 0} | Posts: ${context.posts || 0}
SEO Plugin: ${context.seo_plugin || 'none'}
Translation: ${context.translation_plugin || 'none'}
Languages: ${(context.active_languages || []).join(', ') || 'default'}
Channel: ${channel}

Available actions you can suggest:
${Object.entries(context.available_actions || {}).map(([k,v]) => '- ' + k + ': ' + v).join('\n')}

Rules:
- Be concise and helpful
- Use markdown for formatting (**bold**, lists)
- If the user wants to perform an action, include it in your response as JSON
- For dangerous actions, always ask for confirmation
- Include specific numbers and data when possible
- If you don't know something, say so and suggest what you can do

If you want to suggest an action, end your response with a JSON block:
{"action": "action_type", "params": {}, "confirm": true}

User: ${user.name || 'Admin'} (${user.email || ''})`;

return [{
  json: {
    message,
    conversationId,
    callbackUrl,
    systemPrompt,
    channel
  }
}];

// Parse Claude response
const aiResponse = $input.first().json;
const inputData = $('Build AI Context').first().json;

let responseText = '';
try {
  responseText = aiResponse.content?.[0]?.text || 'I could not process that request.';
} catch (e) {
  responseText = 'Error processing AI response.';
}

// Check if response contains an action suggestion
let actions = [];
const actionMatch = responseText.match(/\{[\s\S]*?"action"[\s\S]*?\}/);
if (actionMatch) {
  try {
    const actionJson = JSON.parse(actionMatch[0]);
    if (actionJson.action) {
      actions.push({
        type: actionJson.action,
        label: actionJson.label || actionJson.action,
        description: actionJson.description || '',
        data: actionJson.params || {},
        confirm: actionJson.confirm !== false
      });
      // Remove action JSON from visible response
      responseText = responseText.replace(actionMatch[0], '').trim();
    }
  } catch (e) {
    // Not valid JSON, ignore
  }
}

const result = {
  conversation_id: inputData.conversationId,
  response: responseText,
  actions: actions,
  channel: inputData.channel
};

// If callback URL provided, also send async callback
if (inputData.callbackUrl) {
  result.callback_url = inputData.callbackUrl;
}

return [{ json: result }];

// Return response directly for webhook mode
const data = $('Parse Response').first().json;
return [{
  json: {
    success: true,
    response: data.response,
    actions: data.actions,
    conversation_id: data.conversation_id
  }
}];
